### Fastify with OpenTelemetry Counter (Agent Bootstrapped)

Source: https://github.com/newrelic/node-newrelic/blob/main/documentation/otel/metrics.md

A robust method for adding an OpenTelemetry counter to a Fastify application. It waits for the New Relic agent's 'otelMetricsBootstrapped' event before initializing metrics and starting the server, ensuring data integrity.

```javascript
'use strict'

const otel = require('@opentelemetry/api')
const metrics = otel.metrics

const server = require('fastify')({
  logger: {
    level: 'info'
  }
})

server.route({
  path: '/',
  method: 'GET',
  handler (req, res) {
    this.metrics['test-counter'].add(1)
    res.send({ hello: 'world' })
  }
})

const newrelic = require('newrelic')
newrelic.agent.on('otelMetricsBootstrapped', () => {
  server.decorate('metrics', {
    'test-counter': metrics.getMeter('test-meter').createCounter('test-counter')
  })
  server.listen({ port: 8080 })
})

```

